<tbody>
<tr class="winner">
<td class="name">Beach Rd / Second Rd loop<small>North–south, both ways</small></td>
<td>Blue baht bus</td>
<td class="price-cell">฿20</td>
<td><span class="rp r-high">Best value</span></td>
</tr>
<tr>
<td class="name">Pattaya → Jomtien Beach<small>Or Naklua / Wong Amat</small></td>
<td>Blue baht bus</td>
<td class="price-cell">฿20–30</td>
<td><span class="rp r-high">Best value</span></td>
</tr>
<tr>
<td class="name">Beach Rd → Bali Hai Pier<small>For the Koh Larn ferry</small></td>
<td>Blue baht bus</td>
<td class="price-cell">฿20</td>
<td><span class="rp r-high">Best value</span></td>
</tr>
<tr>
